 193→const pickFirstNonEmptyString = (...values) => {
 194→    for (const value of values) {
 195→        if (typeof value === 'string') {
 196→            const trimmed = value.trim();
 197→            if (trimmed) return trimmed;
 198→        }
 199→    }
 200→    return '';
 201→};
