 209→const imageFromNodeLike = (nodeLike) => {
 210→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 211→
 212→    const src = pickFirstNonEmptyString(
 213→        nodeLike.src,
 214→        nodeLike.url,
 215→        nodeLike.image_url,
 216→        nodeLike.imageUrl,
 217→        nodeLike?.payload?.src,
 218→        nodeLike?.data?.src
 219→    );
 220→    if (!src) return null;
 221→
 222→    return {
 223→        src,
 224→        width: parseImageDimension(nodeLike.width),
 225→        height: parseImageDimension(nodeLike.height),
 226→    };
 227→};
