 292→const buildShareMetaFromJournal = (journal) => {
 293→    const lexicalData = extractFromLexical(journal?.content);
 294→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
 295→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
 296→    const title = normalizedTitle || 'Untitled Post';
 297→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
 298→
 299→    let description = lexicalData.text || '';
 300→    if (!description && canvasData.text) {
 301→        description = canvasData.text;
 302→    }
 303→    if (!description) {
 304→        description = `Read "${title}" by ${authorName} on Iskryb`;
 305→    }
 306→
 307→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
 308→    let imageCandidateSource = 'fallback';
 309→    if (lexicalData.image?.src) {
 310→        imageCandidate = lexicalData.image.src;
 311→        imageCandidateSource = 'lexical';
 312→    } else if (canvasData.image?.src) {
 313→        imageCandidate = canvasData.image.src;
 314→        imageCandidateSource = 'canvas';
 315→    } else if (journal?.users?.image_url) {
 316→        imageCandidate = journal.users.image_url;
 317→        imageCandidateSource = 'author_avatar';
 318→    }
 319→
 320→    return {
 321→        title,
 322→        normalizedTitle,
 323→        description: toPreviewText(description),
 324→        imageCandidate,
 325→        imageCandidateSource
 326→    };
 327→};
